'use client'

import * as React from 'react'
import { ArrowRight } from 'lucide-react'
import { motion, useReducedMotion, type Variants } from 'motion/react'
import Balancer from 'react-wrap-balancer'

import { Badge } from '@/components/ui/badge'
import { cn } from '@/lib/utils'

import { StudioDemo } from './studio-demo'

export interface Hero11Props {
  title: string
  description: string
  featureLabel?: string
  featureText?: string
  featureHref?: string
  animation?: 'none' | 'subtle'
  variant?: 'standard' | 'compact'
}

const variantStyles = {
  standard: {
    section: 'pt-20 pb-0 sm:pt-28',
    title: 'text-3xl sm:text-4xl md:text-5xl lg:text-[3.25rem]',
    description: 'text-sm sm:text-base leading-relaxed',
    header: 'gap-8 sm:gap-12',
    content: 'gap-12 sm:gap-16',
    studio: 'max-w-5xl',
  },
  compact: {
    section: 'pt-14 pb-0 sm:pt-20',
    title: 'text-2xl sm:text-3xl md:text-4xl',
    description: 'text-sm leading-relaxed',
    header: 'gap-6 sm:gap-8',
    content: 'gap-10 sm:gap-12',
    studio: 'max-w-4xl',
  },
} as const

const container: Variants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.1, delayChildren: 0.05 } },
}

const item: Variants = {
  hidden: { opacity: 0, y: 12, filter: 'blur(6px)' },
  visible: {
    opacity: 1,
    y: 0,
    filter: 'blur(0px)',
    transition: { duration: 0.5, ease: [0.22, 1, 0.36, 1] },
  },
}

const mediaItem: Variants = {
  hidden: { opacity: 0, y: 24, filter: 'blur(8px)' },
  visible: {
    opacity: 1,
    y: 0,
    filter: 'blur(0px)',
    transition: { duration: 0.6, ease: [0.22, 1, 0.36, 1] },
  },
}

function Reveal({
  active,
  variants,
  className,
  children,
}: Readonly<{
  active: boolean
  variants?: Variants
  className?: string
  children: React.ReactNode
}>) {
  if (!active) return <div className={className}>{children}</div>

  return (
    <motion.div variants={variants ?? item} className={className}>
      {children}
    </motion.div>
  )
}

export function Hero11({
  title,
  description,
  featureLabel = 'New',
  featureText,
  featureHref = '#',
  animation = 'none',
  variant = 'standard',
}: Readonly<Hero11Props>) {
  const reduce = useReducedMotion()
  const animate = animation === 'subtle' && !reduce
  const vs = variantStyles[variant]

  const titleElement = title && (
    <h1
      className={cn(
        'text-foreground max-w-xl font-semibold tracking-tight text-balance',
        vs.title,
      )}
    >
      <Balancer>{title}</Balancer>
    </h1>
  )

  const descriptionElement = description && (
    <p className={cn('text-muted-foreground max-w-sm', vs.description)}>
      <Balancer>{description}</Balancer>
    </p>
  )

  const featureElement = featureText && (
    <a
      href={featureHref}
      className="text-foreground group inline-flex items-center gap-2 text-sm font-medium transition-opacity hover:opacity-80 active:scale-[0.96]"
    >
      {featureLabel && (
        <Badge variant="secondary" className="h-5 px-1.5 text-[10px]">
          {featureLabel}
        </Badge>
      )}
      <span>{featureText}</span>
      <ArrowRight className="size-3.5 transition-transform group-hover:translate-x-0.5" />
    </a>
  )

  const headerAside = (descriptionElement || featureElement) && (
    <div className="flex max-w-sm flex-col items-start gap-4 sm:items-end sm:text-right">
      {descriptionElement}
      {featureElement}
    </div>
  )

  const studioElement = (
    <div className={cn('relative mx-auto w-full', vs.studio)}>
      <div
        aria-hidden
        className={cn(
          'pointer-events-none absolute inset-x-8 -inset-y-6 -z-10',
          'bg-[radial-gradient(ellipse_at_center,var(--color-muted)_0%,transparent_70%)]',
          'opacity-70 blur-2xl dark:opacity-30',
        )}
      />
      <div
        className={cn(
          'relative w-full overflow-hidden pb-8 sm:pb-12',
          'mask-b-from-75% mask-b-to-100%',
          'mask-x-from-90% mask-x-to-100%',
          'mask-radial-[85%_75%] mask-radial-from-65% mask-radial-to-100% mask-radial-at-center',
        )}
      >
        <StudioDemo />
      </div>
    </div>
  )

  return (
    <section className="bg-background relative isolate w-full overflow-hidden">
      <motion.div
        className={cn(
          'relative z-10 mx-auto flex max-w-6xl flex-col px-6',
          vs.section,
          vs.content,
        )}
        variants={animate ? container : undefined}
        initial={animate ? 'hidden' : false}
        whileInView={animate ? 'visible' : undefined}
        viewport={{ once: true, margin: '-80px' }}
      >
        <Reveal
          active={animate}
          className={cn(
            'flex w-full flex-col justify-between sm:flex-row sm:items-end',
            vs.header,
          )}
        >
          {titleElement}
          {headerAside}
        </Reveal>

        <Reveal active={animate} variants={mediaItem} className="w-full">
          {studioElement}
        </Reveal>
      </motion.div>
    </section>
  )
}
